#include <stdio.h>

int main(void) {
    int grid[10][10];
    size_t rows, columns;
    if (scanf("%zu %zu", &rows, &columns) != 2 || rows == 0 || columns == 0 || rows > 10 || columns > 10) return 1;
    for (size_t r = 0; r < rows; ++r) for (size_t c = 0; c < columns; ++c) if (scanf("%d", &grid[r][c]) != 1) return 1;
    for (size_t r = 0; r < rows; ++r) {
        long long sum = 0;
        for (size_t c = 0; c < columns; ++c) sum += grid[r][c];
        if (r) putchar(' ');
        printf("%lld", sum);
    }
    putchar('\n');
    return 0;
}
